#include <vector>
#include <string>
#include <algorithm>
#include <regex>
#include <unordered_map>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<string> validBusinessLines = {"electronics", "grocery", "pharmacy", "restaurant"};
    unordered_map<string, int> businessLineOrder = {
        {"electronics", 0},
        {"grocery", 1},
        {"pharmacy", 2},
        {"restaurant", 3}
    };

    auto isValidCoupon = [&](int i) {
        // Check code is not empty and only contains alphanumeric or underscore
        if (code[i].empty() || !regex_match(code[i], regex("^[a-zA-Z0-9_]+$"))) {
            return false;
        }
        // Check businessLine is valid
        if (find(validBusinessLines.begin(), validBusinessLines.end(), businessLine[i]) == validBusinessLines.end()) {
            return false;
        }
        // Check isActive is true
        return isActive[i] == true;
    };

    vector<pair<string, string>> validCoupons;
    for (int i = 0; i < code.size(); i++) {
        if (isValidCoupon(i)) {
            validCoupons.emplace_back(code[i], businessLine[i]);
        }
    }

    sort(validCoupons.begin(), validCoupons.end(), [&](const pair<string, string>& a, const pair<string, string>& b) {
        int orderA = businessLineOrder[a.second];
        int orderB = businessLineOrder[b.second];
        if (orderA != orderB) {
            return orderA < orderB;
        } else {
            return a.first < b.first;
        }
    });

    vector<string> result;
    for (const auto& coupon : validCoupons) {
        result.push_back(coupon.first);
    }
    return result;
}
