using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    const unordered_map<string, int> businessLineOrder = {
        {"electronics", 0},
        {"grocery", 1},
        {"pharmacy", 2},
        {"restaurant", 3}
    };

    vector<pair<string, string>> validCoupons;
    regex codePattern("^[a-zA-Z0-9_]+$");

    for (size_t i = 0; i < code.size(); ++i) {
        if (!isActive[i]) continue;

        if (code[i].empty()) continue;

        if (!regex_match(code[i], codePattern)) continue;

        auto it = businessLineOrder.find(businessLine[i]);
        if (it == businessLineOrder.end()) continue;

        validCoupons.emplace_back(businessLine[i], code[i]);
    }

    sort(validCoupons.begin(), validCoupons.end(), 
        [&businessLineOrder](const pair<string, string>& a, const pair<string, string>& b) {
            int orderA = businessLineOrder.at(a.first);
            int orderB = businessLineOrder.at(b.first);
            if (orderA != orderB) {
                return orderA < orderB;
            } else {
                return a.second < b.second;
            }
        });

    vector<string> result;
    for (const auto& coupon : validCoupons) {
        result.push_back(coupon.second);
    }

    return result;
}
