        // Check businessLine is valid
        if (!validBusinessLines.has(businessLine[i])) {
            return false;
        }
        // Check isActive is true
        return isActive[i] === true;
    };

    const validCoupons = [];
    for (let i = 0; i < code.length; i++) {
        if (isValidCoupon(i)) {
            validCoupons.push({
